#!/usr/bin/env node
/**
 * 0xRay Integration Script
 *
 * Main CLI bridge for external systems (like Jelly commercial modules) to call into 0xRay.
 * Allows spawning OpenCode CLI with 0xRay agents to execute real tasks.
 *
 * @version 1.1.0
 * @since 2026-02-14
 *
 * Usage:
 *   node dist/scripts/integration.js enforcer '{"taskDescription": "Check code quality"}'
 *   node dist/scripts/integration.js --version
 *   node dist/scripts/integration.js --help
 */
import { spawn } from "child_process";
import { resolveAgent } from "../mcps/agent-resolver.js";
import { spawnGate } from "../core/agent-spawn-gate.js";
/**
 * Main entry point for the integration script
 */
async function main() {
    const args = process.argv.slice(2);
    // Handle --version flag
    if (args.includes("--version")) {
        console.log("0xRay Integration v1.1.0");
        process.exit(0);
    }
    // Handle --help flag
    if (args.includes("--help")) {
        console.log(`
0xRay Integration - OpenCode Bridge

Usage:
  node integration.js <agent-name> <task-json>
  node integration.js --version
  node integration.js --help

Examples:
  node integration.js enforcer '{"taskDescription": "Check code quality"}'
  node integration.js architect '{"taskDescription": "Design API endpoints"}'

Flow:
  1. Loads agent configuration from 0xRay
  2. Spawns OpenCode CLI with agent
  3. OpenCode loads 0xRay MCP servers (tools/skills)
  4. Agent executes task using available tools
  5. Results returned as JSON
    `);
        process.exit(0);
    }
    // Validate arguments
    if (args.length < 2) {
        console.error("Error: Missing arguments");
        console.error("Usage: node integration.js <agent-name> <task-json>");
        process.exit(1);
    }
    const agentName = args[0];
    let taskContext;
    // Parse task JSON
    try {
        taskContext = JSON.parse(args[1]);
    }
    catch (error) {
        console.error("Error: Invalid JSON task context");
        process.exit(1);
    }
    // Execute the integration
    try {
        // Get agent configuration from 0xRay registry
        const agent = await resolveAgent(agentName);
        console.log(`[0xRay] Spawning OpenCode with agent: ${agentName}`);
        console.log(`[0xRay] Task: ${taskContext.taskDescription || "No description"}`);
        // Build the task prompt for OpenCode
        const taskPrompt = buildTaskPrompt(agent, taskContext);
        // Spawn OpenCode CLI
        const result = await spawnOpenCode(agentName, taskPrompt);
        // Output JSON result
        const output = {
            success: true,
            agent: agentName,
            task: taskContext.taskDescription,
            result,
            timestamp: new Date().toISOString(),
        };
        console.log(JSON.stringify(output, null, 2));
    }
    catch (error) {
        const errorOutput = {
            success: false,
            agent: agentName,
            error: error instanceof Error ? error.message : String(error),
            timestamp: new Date().toISOString(),
        };
        console.error(JSON.stringify(errorOutput, null, 2));
        process.exit(1);
    }
}
/**
 * Build task prompt from agent configuration
 */
function buildTaskPrompt(agent, taskContext) {
    const availableTools = agent.tools?.include?.join(", ") || "read, grep, edit, bash commands";
    return `You are the ${agent.name} agent.

${agent.system || ""}

## Your Task
${taskContext.taskDescription}

## Context
${JSON.stringify(taskContext.context || {}, null, 2)}

## Available Tools
${availableTools}

Execute this task using the available tools. Be thorough and provide detailed results.`;
}
/**
 * Spawn OpenCode CLI process
 */
function spawnOpenCode(agentName, prompt) {
    // Gate: prevent spawning unless explicitly enabled
    spawnGate.assertAllowed("integration-script");
    let isFinished = false;
    return new Promise((resolve, reject) => {
        // Spawn opencode with stdin for prompt - more reliable
        let opencode;
        try {
            opencode = spawn("opencode", ["run", "-", "--agent", agentName, "-m", "opencode/big-pickle"], {
                cwd: process.cwd(),
                env: {
                    ...process.env,
                    NODE_ENV: "production",
                    OPENCODE_MCP_CONFIG: "./node_modules/strray-ai/opencode.json",
                },
                stdio: ["pipe", "pipe", "pipe"],
            });
            if (opencode.pid) {
                spawnGate.trackProcess(opencode.pid, "integration-script", `agent=${agentName}`);
            }
        }
        catch (error) {
            const msg = error instanceof Error && "code" in error && error.code === "ENOENT"
                ? "OpenCode CLI not found. Please install opencode to use this command."
                : `Failed to spawn opencode: ${error instanceof Error ? error.message : String(error)}`;
            reject(new Error(msg));
            return;
        }
        // Write prompt to stdin
        opencode.stdin?.write(prompt);
        opencode.stdin?.end();
        let stdout = "";
        let stderr = "";
        if (opencode.stdout) {
            opencode.stdout.on("data", (data) => {
                stdout += data.toString();
            });
        }
        if (opencode.stderr) {
            opencode.stderr.on("data", (data) => {
                stderr += data.toString();
            });
        }
        // Graceful cleanup function
        const cleanup = (force = false) => {
            if (isFinished)
                return;
            isFinished = true;
            if (force && opencode.pid !== undefined && !opencode.killed) {
                try {
                    process.kill(opencode.pid, "SIGTERM");
                    // Give it 2 seconds to terminate gracefully, then force kill
                    setTimeout(() => {
                        if (!opencode.killed && opencode.pid !== undefined) {
                            try {
                                process.kill(opencode.pid, "SIGKILL");
                            }
                            catch (e) {
                                // Process already dead
                            }
                        }
                    }, 2000);
                }
                catch (e) {
                    // Process already dead
                }
            }
        };
        opencode.on("close", (code) => {
            cleanup(false);
            if (opencode.pid) {
                spawnGate.untrackProcess(opencode.pid);
            }
            if (code !== 0) {
                reject(new Error(`OpenCode exited with code ${code}: ${stderr}`));
                return;
            }
            try {
                // Try to parse JSON output
                const result = JSON.parse(stdout);
                resolve(result);
            }
            catch (e) {
                // Return raw output if not JSON
                resolve({ output: stdout, errors: stderr });
            }
        });
        opencode.on("error", (error) => {
            cleanup(true);
            if (error.code === "ENOENT") {
                reject(new Error("OpenCode CLI not found. Please install: npm install -g opencode-ai"));
            }
            else {
                reject(error);
            }
        });
        // Timeout after 5 minutes - graceful first, then force
        const timeout = setTimeout(() => {
            console.log("[0xRay] OpenCode timed out, terminating...");
            cleanup(true);
            reject(new Error("OpenCode execution timeout (5 minutes)"));
        }, 300000);
        // Clear timeout on successful close
        opencode.on("close", () => {
            clearTimeout(timeout);
        });
    });
}
// Execute main function
main().catch((error) => {
    console.error("Fatal error:", error);
    process.exit(1);
});
